from dataclasses import dataclass
from typing import Any, Optional

@dataclass
class Event:
    start: float
    end: float
    title: str
    priority: int  # higher = more important

class Calendar:
    def __init__(self):
        self.events: list[Event] = []

    def _clip_intervals(self, intervals: list[tuple[float, float]], start: float, end: float) -> list[tuple[float, float]]:
        res = []
        for s, e in intervals:
            if e <= start or s >= end:
                res.append((s, e))
            else:
                if s < start:
                    res.append((s, start))
                if end < e:
                    res.append((end, e))
        return res

    def add_event(self, event: Event) -> list[Event]:
        if event.start >= event.end:
            raise ValueError("Start must be less than end")

        new_intervals = [(event.start, event.end)]
        removed: list[Event] = []
        modified: list[tuple[Event, list[tuple[float, float]]]] = []

        for e in self.events:
            if e.start < event.end and e.end > event.start:
                if event.priority > e.priority:
                    removed.append(e)
                    e_frags = []
                    if e.start < event.start:
                        e_frags.append((e.start, event.start))
                    if event.end < e.end:
                        e_frags.append((event.end, e.end))
                    modified.append((e, e_frags))
                    new_intervals = self._clip_intervals(new_intervals, event.start, event.end)
                else:
                    new_intervals = self._clip_intervals(new_intervals, e.start, e.end)

        for e, frags in modified:
            self.events.remove(e)
            for s, end in frags:
                self.events.append(Event(s, end, e.title, e.priority))

        for s, end in new_intervals:
            if s < end:
                self.events.append(Event(s, end, event.title, event.priority))

        return removed + [e for e, _ in modified]

    def get_events(self, start: float, end: float) -> list[Event]:
        return sorted(
            [e for e in self.events if e.start < end and e.end > start],
            key=lambda e: e.start
        )

    def free_slots(self, start: float, end: float, min_duration: float = 0) -> list[tuple[float, float]]:
        events = self.get_events(start, end)
        if not events:
            if end - start >= min_duration:
                return [(start, end)]
            return []

        slots = []
        current = start
        for e in events:
            if e.start > current:
                slot_len = e.start - current
                if slot_len >= min_duration:
                    slots.append((current, e.start))
            current = max(current, e.end)

        if current < end:
            slot_len = end - current
            if slot_len >= min_duration:
                slots.append((current, end))

        return slots

    def utilization(self, start: float, end: float) -> float:
        if end <= start:
            return 0.0
        occupied = 0.0
        for e in self.get_events(start, end):
            overlap_start = max(e.start, start)
            overlap_end = min(e.end, end)
            if overlap_end > overlap_start:
                occupied += overlap_end - overlap_start
        return occupied / (end - start)
